sys_script_fix.script:
var log = function(m) { gs.info('[ChainDemo] ' + m); };

 var OWNER_EMAIL = 'luizgalvao.dev@gmail.com';
 var MANAGER_EMAIL = 'luizmedeiros324@gmail.com';

 var managerUserNames = ['abraham.lincoln','charles.beckley','george.washington','taylor.vreeland','megan.burke'];
 var processed = 0;  

 for (var i = 0; i < managerUserNames.length; i++) {
     if (updateUser(managerUserNames[i], MANAGER_EMAIL)) processed++;
 }

 var owners = new GlideRecord('sys_user');
 owners.addQuery('x_1880990_chain_u_chain_external_sys_id', '!=', '');
 owners.query();
 while (owners.next()) {
     if (updateUser(owners.user_name.toString(), OWNER_EMAIL)) processed++;
 }

 log('=== Total atualizados: ' + processed + ' ===');

 function updateUser(userName, newEmail) {
     var u = new GlideRecord('sys_user');
     u.addQuery('user_name', userName);
     u.query();
     if (!u.next()) { gs.error('[ChainDemo] user nao encontrado: ' + userName); return false; }

     u.email = newEmail;
     u.update();
     log('user updated: ' + userName + ' -> ' + newEmail);

     var dev = new GlideRecord('cmn_notif_device');
     dev.addQuery('user', u.sys_id.toString());
     dev.addQuery('type', 'Email');
     dev.query();
     if (dev.next()) {
         dev.email_address = newEmail;
         dev.active = true;
         dev.update();
         log('device updated: ' + userName);
     } else {
         var nd = new GlideRecord('cmn_notif_device');
         nd.initialize();
         nd.user = u.sys_id.toString();
         nd.type = 'Email';
         nd.name = 'Primary Email';
         nd.email_address = newEmail;
         nd.active = true;
         nd.insert();
         log('device created: ' + userName);
     }
     return true;
 }
